<style>
.admin-info-panel,.admin-shop-section,.admin-form-panel,.admin-side-panel{border:1px solid var(--border);background:rgba(8,12,28,.62);border-radius:8px}.admin-info-panel{margin-bottom:18px;overflow:hidden}.admin-info-head,.admin-shop-head{display:flex;justify-content:space-between;align-items:center;gap:14px;padding:18px 20px;cursor:pointer;border-bottom:1px solid rgba(60,120,255,.12)}.admin-info-title,.admin-shop-title,.admin-form-panel-title{font-family:var(--font-title);letter-spacing:4px;text-transform:uppercase;color:var(--blue-bright)}.admin-info-sub,.admin-shop-sub{font-size:.9rem;color:var(--silver-dim);font-style:italic;margin-top:4px}.admin-info-body{padding:18px 20px;display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:14px}.admin-info-card{border:1px solid rgba(60,120,255,.16);background:rgba(0,0,0,.18);border-radius:6px;padding:14px}.admin-info-card h4{font-family:var(--font-title);color:var(--blue-bright);letter-spacing:2px;text-transform:uppercase;font-size:.78rem;margin-bottom:8px}.admin-info-card p,.admin-info-card li{color:var(--silver-dim);line-height:1.55;font-size:.95rem}.admin-info-card ul{padding-left:18px}.admin-toolbar{display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap;margin-bottom:18px}.admin-switch-btn,.admin-small-btn{font-family:var(--font-title);letter-spacing:2px;text-transform:uppercase;border:1px solid var(--border);background:rgba(60,120,255,.04);color:var(--blue-bright);border-radius:4px;padding:10px 14px;cursor:pointer;text-decoration:none;display:inline-flex;align-items:center;justify-content:center;gap:8px}.admin-switch-btn:hover,.admin-small-btn:hover{border-color:var(--blue);background:rgba(60,120,255,.11)}.admin-shop-section{margin-bottom:18px;overflow:hidden}.admin-shop-section.is-closed .admin-shop-body{display:none}.admin-shop-section.is-closed .admin-shop-head{border-bottom:none}.admin-shop-head .admin-small-btn{min-width:104px}.admin-shop-body{padding:18px}.admin-mejoras-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(330px,1fr));gap:14px;align-items:stretch}.admin-mejora-card{display:flex;flex-direction:column;gap:12px;min-height:100%;padding:16px;border-radius:8px;border:1px solid rgba(60,120,255,.22);background:rgba(5,10,24,.78);position:relative;overflow:hidden}.admin-mejora-card:before{content:'';position:absolute;inset:0 0 auto 0;height:2px;background:linear-gradient(90deg,transparent,var(--tier-color,var(--blue)),transparent);opacity:.85}.admin-mejora-card[data-tier=dorada]{border-color:rgba(255,215,0,.28)}.admin-mejora-card[data-tier=morada]{border-color:rgba(180,100,255,.34)}.admin-mejora-card[data-tier=desactivada]{opacity:.78;border-style:dashed}.admin-mejora-top{display:flex;justify-content:space-between;align-items:flex-start;gap:10px}.admin-mejora-name{font-family:var(--font-title);color:var(--tier-color,var(--blue-bright));letter-spacing:2px;text-transform:uppercase;font-size:1rem;line-height:1.15}.admin-mejora-type{font-family:var(--font-title);color:var(--silver-dim);letter-spacing:2px;text-transform:uppercase;font-size:.62rem;margin-top:5px;overflow-wrap:anywhere}.admin-status-badge{font-family:var(--font-title);letter-spacing:1.5px;text-transform:uppercase;font-size:.62rem;padding:5px 8px;border-radius:3px;flex-shrink:0}.admin-status-badge.on{color:#44ff88;border:1px solid rgba(0,200,100,.35);background:rgba(0,200,100,.12)}.admin-status-badge.off{color:#ff7788;border:1px solid rgba(255,51,68,.35);background:rgba(255,51,68,.1)}.admin-mejora-desc{color:var(--silver-dim);line-height:1.45;font-size:.92rem;min-height:2.6em}.admin-metric-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:8px}.admin-metric{border:1px solid rgba(60,120,255,.14);background:rgba(255,255,255,.025);border-radius:5px;padding:10px;min-width:0}.admin-metric-label{display:block;font-family:var(--font-title);color:var(--silver-dim);letter-spacing:2px;text-transform:uppercase;font-size:.56rem;margin-bottom:4px}.admin-metric-value{color:var(--silver);font-family:var(--font-title);font-size:.9rem;overflow-wrap:anywhere}.admin-mejora-detail{display:none;border-top:1px solid rgba(60,120,255,.12);padding-top:10px}.admin-mejora-card.is-open .admin-mejora-detail{display:block}.admin-detail-row{display:flex;justify-content:space-between;gap:12px;padding:6px 0;color:var(--silver-dim);font-size:.9rem}.admin-detail-row strong{color:var(--silver);font-family:var(--font-title);letter-spacing:1px}.admin-diagnostics{display:flex;flex-direction:column;gap:6px;margin-top:8px}.admin-diagnostic{border:1px solid rgba(255,215,0,.32);background:rgba(255,215,0,.06);color:#ffd866;border-radius:4px;padding:8px 10px;font-size:.82rem}body.hide-shop-suggestions .admin-diagnostics{display:none}.admin-mejora-actions{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:auto}.admin-mejora-actions .btn-admin{text-align:center;width:100%}.admin-empty-box{padding:22px;color:var(--silver-dim);font-style:italic}.admin-form-layout{display:grid;grid-template-columns:minmax(0,1.1fr) minmax(320px,.9fr);gap:18px;align-items:start}.admin-form-panel,.admin-side-panel{padding:18px}.admin-form-panel-title{margin-bottom:16px}.admin-form-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:16px}.admin-form-grid .full{grid-column:1/-1}.admin-form-actions{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:18px}.admin-form-actions .btn-admin,.admin-form-actions .admin-form-submit{width:100%;text-align:center;justify-content:center}.admin-help-block{border:1px solid rgba(60,120,255,.15);background:rgba(0,0,0,.16);border-radius:6px;padding:12px;color:var(--silver-dim);line-height:1.45;font-size:.92rem;margin-bottom:12px}.admin-preview-costs{display:grid;grid-template-columns:repeat(2,1fr);gap:8px;margin-top:8px}@media(max-width:980px){.admin-form-layout{grid-template-columns:1fr}}@media(max-width:700px){.admin-toolbar{align-items:stretch}.admin-toolbar>*{width:100%}.admin-mejoras-grid{grid-template-columns:1fr}.admin-form-grid{grid-template-columns:1fr}.admin-form-actions{grid-template-columns:1fr}.admin-shop-head,.admin-info-head{align-items:flex-start;flex-direction:column}.admin-shop-head .admin-small-btn{width:100%}}
</style>
